// Midpoint displacement: click 'Generate' to see recursion levels
const canvas = document.createElement('canvas');
canvas.width = 580; canvas.height = 280;
canvas.style.background = '#0a0a2e';
canvas.style.borderRadius = '12px';
container.appendChild(canvas);
const ctx = canvas.getContext('2d');

const controls = document.createElement('div');
controls.style.cssText = 'display:flex;gap:12px;margin-top:8px;align-items:center';
const btn = document.createElement('button');
btn.textContent = '⚡ Generate Level by Level';
btn.style.cssText = 'padding:8px 16px;border-radius:8px;background:#7c3aed;color:white;border:none;cursor:pointer;font-weight:600';
const label = document.createElement('span');
label.style.cssText = 'color:#a78bfa;font-size:14px';
label.textContent = 'Click to start';
controls.appendChild(btn); controls.appendChild(label);
container.appendChild(controls);

let level = 0;
let points = [{x: 40, y: 140}, {x: 540, y: 140}];
const colors = ['#ef4444','#f59e0b','#22c55e','#3b82f6','#a855f7','#ec4899'];

function draw() {
  ctx.clearRect(0,0,580,280);
  ctx.shadowBlur = 15;
  ctx.shadowColor = colors[Math.min(level, colors.length-1)] || '#a855f7';
  ctx.strokeStyle = colors[Math.min(level, colors.length-1)] || '#a855f7';
  ctx.lineWidth = Math.max(4 - level * 0.5, 1.5);
  ctx.beginPath();
  ctx.moveTo(points[0].x, points[0].y);
  for (let i = 1; i < points.length; i++) ctx.lineTo(points[i].x, points[i].y);
  ctx.stroke();
  // Draw endpoints as circles
  for (const p of points) {
    ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI*2);
    ctx.fillStyle = '#fff'; ctx.fill();
  }
  ctx.shadowBlur = 0;
  // Labels
  ctx.fillStyle = '#94a3b8'; ctx.font = '13px sans-serif';
  ctx.fillText('Start', 30, 170);
  ctx.fillText('End', 520, 170);
  ctx.fillStyle = colors[Math.min(level, colors.length-1)];
  ctx.font = 'bold 14px sans-serif';
  ctx.fillText('Level ' + level + ' — ' + points.length + ' points', 220, 20);
}

btn.onclick = () => {
  if (level >= 6) { level = 0; points = [{x:40,y:140},{x:540,y:140}]; draw(); label.textContent = 'Reset! Click again.'; return; }
  const newPoints = [points[0]];
  for (let i = 0; i < points.length - 1; i++) {
    const a = points[i], b = points[i+1];
    const displacement = (Math.random()-0.5) * (120 / (level+1));
    newPoints.push({x: (a.x+b.x)/2, y: (a.y+b.y)/2 + displacement});
    newPoints.push(b);
  }
  points = newPoints;
  level++;
  draw();
  const msgs = ['Two endpoints set','Midpoint added — big structure','4 points — paragraph-level','8 points — getting detailed','16 points — fine structure','32+ points — token-level detail'];
  label.textContent = 'Level ' + level + ': ' + (msgs[level-1]||'Maximum detail');
};
draw();

// Interactive narrative tree — click nodes to expand
const wrap = document.createElement('div');
wrap.style.cssText = 'font-family:system-ui;color:#e2e8f0;';
container.appendChild(wrap);

const tree = {
  text: 'Story arc',
  children: [
    { text: '🟢 John is healthy', leaf: true, level: 0 },
    { text: '❓ Click to generate midpoint', expandable: true, left: 'John is healthy', right: 'John is in hospital', level: 1 },
    { text: '🔴 John is in the hospital', leaf: true, level: 0 }
  ]
};

const midpoints = {
  'John is healthy|John is in hospital': [
    { text: '🟡 John gets hit by a car', children: [
      { text: '🟢 John is healthy', leaf: true, level: 0 },
      { text: '❓ Click to fill', expandable: true, left: 'healthy', right: 'hit by car', level: 2 },
      { text: '🟡 John gets hit by a car', leaf: true, level: 1 },
      { text: '❓ Click to fill', expandable: true, left: 'hit by car', right: 'hospital', level: 2 },
      { text: '🔴 John is in the hospital', leaf: true, level: 0 }
    ]}
  ],
  'healthy|hit by car': [
    { text: '🟠 John crosses a busy street without looking', leaf: true, level: 2 }
  ],
  'hit by car|hospital': [
    { text: '🟠 A bystander calls 911, ambulance arrives', leaf: true, level: 2 }
  ]
};

const levelColors = ['#ef4444','#f59e0b','#22c55e','#3b82f6','#a855f7'];

function render(node, depth=0) {
  const div = document.createElement('div');
  div.style.cssText = `margin-left:${depth*24}px;padding:6px 12px;margin:4px 0;border-radius:8px;font-size:14px;`;

  if (node.expandable) {
    div.style.background = 'rgba(139,92,246,0.15)';
    div.style.cursor = 'pointer';
    div.style.border = '1px dashed rgba(139,92,246,0.4)';
    div.textContent = node.text;
    div.onclick = () => {
      const key = node.left + '|' + node.right;
      const result = midpoints[key];
      if (result) {
        if (result[0].children) {
          // Replace entire tree display
          tree.children = result[0].children;
          wrap.innerHTML = '';
          wrap.appendChild(renderInfo());
          tree.children.forEach(c => wrap.appendChild(render(c, 0)));
        } else {
          div.style.background = 'rgba(34,197,94,0.15)';
          div.style.border = '1px solid rgba(34,197,94,0.3)';
          div.style.cursor = 'default';
          div.textContent = result[0].text;
          div.onclick = null;
        }
      }
    };
  } else {
    const c = levelColors[node.level] || '#94a3b8';
    div.style.background = `${c}15`;
    div.style.borderLeft = `3px solid ${c}`;
    div.textContent = node.text;
  }
  return div;
}

function renderInfo() {
  const info = document.createElement('div');
  info.style.cssText = 'color:#94a3b8;font-size:13px;margin-bottom:8px;padding:4px 8px;';
  info.innerHTML = '🌳 <b>Narrative tree</b> — click purple nodes to generate midpoints';
  return info;
}

wrap.appendChild(renderInfo());
tree.children.forEach(c => wrap.appendChild(render(c, 0)));

const wrap = document.createElement('div');
wrap.style.cssText = 'font-family:system-ui;color:#e2e8f0;';
container.appendChild(wrap);

const paradigms = [
  { name: 'Autoregressive (GPT)', icon: '➡️', depth: 'O(n)', parallel: '❌ None', coherence: '⚠️ Drifts', color: '#ef4444',
    desc: 'Generates left-to-right, one token at a time. Fast locally but can lose the plot over long sequences.' },
  { name: 'Flat Diffusion', icon: '🌫️', depth: 'O(T steps)', parallel: '✅ Per step', coherence: '⚠️ Global blur', color: '#f59e0b',
    desc: 'Refines all positions simultaneously from noise. Parallel within each step, but needs many steps and can lose global structure.' },
  { name: 'Recursive Midpoint', icon: '⚡', depth: 'O(log n)', parallel: '✅✅ Per level', coherence: '✅ Locked in', color: '#22c55e',
    desc: 'Endpoints first, then recursive infilling. Logarithmic depth, massively parallel at each level, global coherence by construction.' }
];

const table = document.createElement('div');
table.style.cssText = 'display:grid;gap:12px;';

paradigms.forEach(p => {
  const card = document.createElement('div');
  card.style.cssText = `padding:16px;border-radius:12px;background:rgba(30,30,60,0.6);border-left:4px solid ${p.color};cursor:pointer;transition:all 0.2s`;
  card.innerHTML = `
    <div style="display:flex;justify-content:space-between;align-items:center">
      <span style="font-size:16px;font-weight:600">${p.icon} ${p.name}</span>
      <span style="font-size:12px;color:#94a3b8">click to expand</span>
    </div>
    <div style="display:flex;gap:20px;margin-top:8px;font-size:13px">
      <span>Depth: <b style="color:${p.color}">${p.depth}</b></span>
      <span>Parallel: ${p.parallel}</span>
      <span>Coherence: ${p.coherence}</span>
    </div>
    <div class="desc" style="display:none;margin-top:8px;font-size:13px;color:#cbd5e1;line-height:1.5">${p.desc}</div>
  `;
  card.onclick = () => {
    const desc = card.querySelector('.desc');
    desc.style.display = desc.style.display === 'none' ? 'block' : 'none';
  };
  table.appendChild(card);
});
wrap.appendChild(table);

const note = document.createElement('p');
note.style.cssText = 'color:#64748b;font-size:12px;margin-top:12px;';
note.textContent = 'Click each card to see details. For n=10,000 tokens: GPT needs ~10,000 steps, flat diffusion ~1,000 steps, recursive midpoint ~14 levels.';
wrap.appendChild(note);

const wrap = document.createElement('div');
wrap.style.cssText = 'font-family:system-ui;color:#e2e8f0;display:grid;grid-template-columns:1fr 1fr;gap:12px;';
container.appendChild(wrap);

const components = [
  { name: 'Anchor Encoder', icon: '🎯', color: '#3b82f6', desc: 'Takes two SAE feature vectors → produces midpoint prior distribution. The encoder learns what kind of content naturally bridges two semantic anchors.' },
  { name: 'Midpoint Diffusion', icon: '🌀', color: '#a855f7', desc: 'Denoises from prior, conditioned on both anchors + recursion depth. Uses the anchor encoder output as a strong prior, so it only needs to fill in local detail.' },
  { name: 'Feature Cascade', icon: '📊', color: '#22c55e', desc: 'Maps recursion depth → which SAE feature levels to activate/enforce. Level 0 = topic features. Level 3 = rhetorical features. Level 6+ = syntactic features.' },
  { name: 'Scheduler', icon: '📋', color: '#f59e0b', desc: 'Manages the binary tree of intervals, dispatches midpoint jobs to workers. Handles the MapReduce orchestration across GPUs/machines.' }
];

components.forEach(c => {
  const card = document.createElement('div');
  card.style.cssText = `padding:16px;border-radius:12px;background:rgba(30,30,60,0.6);border:1px solid ${c.color}33;cursor:pointer;transition:all 0.3s`;
  card.innerHTML = `<div style="font-size:24px;margin-bottom:8px">${c.icon}</div><div style="font-weight:700;color:${c.color};margin-bottom:4px">${c.name}</div><div style="font-size:13px;color:#94a3b8;line-height:1.5">${c.desc}</div>`;
  card.onmouseenter = () => card.style.borderColor = c.color;
  card.onmouseleave = () => card.style.borderColor = c.color + '33';
  wrap.appendChild(card);
});
